_deriveBestOfLists(){
  const all = (A.getRestaurants()||[]).filter(r=>r && !r.suburb);
  if(!all.length) return [];
  // Rank Best-Of picks to mirror real-world consensus (Michelin/JBF/media/res-difficulty/
  // longevity/group pedigree) rather than pure editorial score:
  //   rank = unifiedScore (0.7 editorial + 0.3 algo composite)
  //        + signature-dish-position boost (dish at index 0 is the restaurant's calling card)
  //        + bestOf[] array boost (card's own editorial flag for this dish)
  const rankFor = (r, cat) => {
    const dishes = Array.isArray(r.dishes) ? r.dishes : [];
    const matchIdx = dishes.findIndex(d=>cat.test(String(d||'')));
    const base = (typeof this.unifiedScore === 'function') ? this.unifiedScore(r) : (r.score||0);
    const sig  = matchIdx === 0 ? 4 : matchIdx === 1 ? 2 : matchIdx === 2 ? 1 : 0;
    const flagged = (r.bestOf||[]).some(b=>{
      const s = String(b||'').toLowerCase();
      return s && (s.includes(cat.key) || cat.key.includes(s));
    });
    const bestOfBoost = flagged ? 5 : 0;
    return base + sig + bestOfBoost;
  };
  const lists = [];
  const seen = new Set();
  for(const cat of this._bestOfCategories()){
    const hits = all.filter(r=>Array.isArray(r.dishes) && r.dishes.some(d=>cat.test(String(d||''))));
    if(hits.length < 3) continue;
    if(seen.has(cat.title)) continue;
    seen.add(cat.title);
    hits.sort((a,b)=>rankFor(b,cat) - rankFor(a,cat));
    lists.push({
      title: cat.title,
      emoji: cat.emoji,
      spots: hits.slice(0,6).map(r=>({ name: r.name, note: this._deriveBestOfNote(r) }))
    });
  }
  return lists;
},



