#!/usr/bin/env node
// Fix Best Of data and logic for Dallas accuracy overhaul.
// Run from repo root: node scripts/fix-bestof-dallas.js

const fs = require('fs');
const path = require('path');

const filePath = path.join(__dirname, '..', 'index.html');
let content = fs.readFileSync(filePath, 'utf8');

// ─── 1. Update DALLAS_DATA bestOf arrays ────────────────────────────────────

const marker = 'const DALLAS_DATA=[';
const markerStart = content.indexOf(marker);
if (markerStart === -1) throw new Error('DALLAS_DATA not found');
const arrStart = markerStart + marker.length - 1; // position of opening '['

let depth = 0, arrEnd = arrStart;
for (let i = arrStart; i < content.length; i++) {
  if (content[i] === '[') depth++;
  else if (content[i] === ']') { depth--; if (depth === 0) { arrEnd = i + 1; break; } }
}

const arr = JSON.parse(content.slice(arrStart, arrEnd));

const bestOfUpdates = {
  // Best Burger
  518: ['#1 Best Burger (Eater Dallas)', '#1 Best Smash Burger'],           // Maple & Motor
  359: ['#2 Best Burger', '#1 Best Classic Drive-In Burger'],               // Keller's Drive-In
  52:  ['#3 Best Burger', '#1 Best Craft Burger'],                           // Rodeo Goat
  363: ['#5 Best Burger', '#1 Best Dive Bar Burger'],                        // Angry Dog
  // Burger Schmurger (430) already has "#1 Best Burger in Dallas"

  // Best Tacos
  55:  ['#1 Best Tacos (Dallas)', '#1 Best Cheap Tacos'],                    // Fuel City Tacos (was ["Mexican"])
  233: ['#2 Best Tacos', '#1 Best Artisan Tacos'],                           // Revolver Taco Lounge
  1096: ['#3 Best Tacos', '#1 Best Gourmet Tacos'],                          // Velvet Taco
  554: ['#4 Best Tacos', '#1 Best Neighborhood Taqueria'],                   // La Lupita Taco & Mezcal
  471: ['#5 Best Tacos'],                                                     // Resident Taqueria

  // Best Steak
  99:  ['#2 Best Steakhouse', '#1 Best Classic Steakhouse'],                 // Bob's Steak & Chop House
  49:  ['#3 Best Steakhouse', '#1 Best Uptown Steakhouse'],                  // Nick & Sam's
  73:  ['#4 Best Steakhouse', '#1 Best Modern Steakhouse'],                  // Town Hearth
  // Al Biernat's (23) already has "#1 Best Steakhouse"
  // Pappas Bros (43) already has "#1 Best Steakhouse Downtown"

  // Best Brisket — add "brisket" keyword to existing BBQ entries
  // (handled below as merges, not replacements)

  // Best Pizza
  348: ['#2 Best Pizza (Eater Dallas)', '#1 Best Neapolitan Pizza'],         // Cane Rosso
  347: ['#3 Best Pizza', '#1 Best Artisan Pizza'],                           // Pie Tap
  211: ['#4 Best Pizza', '#1 Best NY-Style Pizza'],                          // Serious Pizza
  509: ['#5 Best Pizza', '#2 Best NY-Style Pizza'],                          // Zoli's
  // Olivella's (435) already has "#1 Best Pizza in Texas (USA Today)"
};

// Brisket: merge "brisket" entries into existing BBQ bestOf arrays
const brisketMerges = {
  57:  '#1 Best Brisket',   // Pecan Lodge
  462: '#2 Best Brisket',   // Terry Black's
  14:  '#1 Best Brisket',   // Cattleack Barbeque
  205: ['#3 Best Brisket', '#4 Best BBQ'],  // The Slow Bone (no existing bestOf)
  478: '#4 Best Brisket',   // Hutchins BBQ
};

let updated = 0;
arr.forEach(r => {
  if (bestOfUpdates[r.id] !== undefined) {
    r.bestOf = bestOfUpdates[r.id];
    updated++;
  }
  if (brisketMerges[r.id] !== undefined) {
    const toAdd = Array.isArray(brisketMerges[r.id]) ? brisketMerges[r.id] : [brisketMerges[r.id]];
    r.bestOf = [...toAdd, ...(r.bestOf || [])];
    updated++;
  }
});

console.log(`Updated ${updated} restaurant bestOf entries`);

// Verify key restaurants
const check = [430, 23, 43, 435].concat(Object.keys(bestOfUpdates).map(Number)).concat(Object.keys(brisketMerges).map(Number));
[...new Set(check)].forEach(id => {
  const r = arr.find(x => x.id === id);
  if (r) console.log(`  ID ${id} ${r.name}: ${JSON.stringify(r.bestOf)}`);
});

// Serialize the updated array back (compact, single-line to match existing format)
const newArrStr = JSON.stringify(arr);
content = content.slice(0, arrStart) + newArrStr + content.slice(arrEnd);

// ─── 2. Update _deriveBestOfLists logic ─────────────────────────────────────

// 2a. Increase bestOfBoost from 5 to 30 (bestOf is now primary signal)
content = content.replace(
  'const bestOfBoost = flagged ? 5 : 0;',
  'const bestOfBoost = flagged ? 30 : 0;'
);

// 2b. Exclude 'attractions' and 'coffee' venues for food categories (skipBars already excludes bars)
content = content.replace(
  "if(cat.skipBars && this.classify(r) === 'bars') return false;",
  "if(cat.skipBars){\n        const cls=this.classify(r);\n        if(cls==='bars'||cls==='attractions'||cls==='coffee'||cls==='dessert') return false;\n      }"
);

// 2c. Add cuisineBlock check: dishMatch only; bestOfMatch overrides
const oldFilter = "const dishMatch = Array.isArray(r.dishes) && r.dishes.some(d=>cat.test(String(d||'')));\n        // Also eligible if explicitly ranked in bestOf for this category\n        const bestOfMatch = (r.bestOf||[]).some(b=>String(b||'').toLowerCase().includes(cat.key));\n        return dishMatch || bestOfMatch;";
const newFilter = "const bestOfMatch = (r.bestOf||[]).some(b=>String(b||'').toLowerCase().includes(cat.key));\n        if(bestOfMatch) return true;\n        if(cat.cuisineBlock && cat.cuisineBlock.test(String(r.cuisine||'').toLowerCase())) return false;\n        return Array.isArray(r.dishes) && r.dishes.some(d=>cat.test(String(d||'')));";
content = content.replace(oldFilter, newFilter);

// 2d. Cap at 5 instead of 6
content = content.replace(
  'spots: hits.slice(0,6).map(r=>({ name: r.name, note: this._deriveBestOfNote(r) }))',
  'spots: hits.slice(0,5).map(r=>({ name: r.name, note: this._deriveBestOfNote(r) }))'
);

// ─── 3. Add cuisineBlock to _bestOfCategories ────────────────────────────────

// Best Tacos: block Asian/Vietnamese/Japanese cuisines from dishMatch
content = content.replace(
  "{ title:\"Best Tacos\",            emoji:'🌮', key:'tacos',            test:d=>/\\btacos?\\b/i.test(d) && !/taco\\s*salad|fish\\s*taco|breakfast\\s*taco/i.test(d), skipBars:true }",
  "{ title:\"Best Tacos\",            emoji:'🌮', key:'tacos',            test:d=>/\\btacos?\\b/i.test(d) && !/taco\\s*salad|fish\\s*taco|breakfast\\s*taco/i.test(d), skipBars:true, cuisineBlock:/pan[\\s-]?asian|vietnamese|japanese|sushi|korean|thai|chinese/i }"
);

// Best Steak: block French bistros from dishMatch (French cafes already excluded via 'coffee' class)
content = content.replace(
  "{ title:\"Best Steak\",            emoji:'🥩', key:'steak',            test:d=>/\\b(ribeye|porterhouse|tomahawk|new\\s*york\\s*strip|filet\\s*mignon|\\bsteak\\b)/i.test(d) && !/chicken[\\s-]?fried|pastrami\\s*burger/i.test(d), skipBars:true }",
  "{ title:\"Best Steak\",            emoji:'🥩', key:'steak',            test:d=>/\\b(ribeye|porterhouse|tomahawk|new\\s*york\\s*strip|filet\\s*mignon|\\bsteak\\b)/i.test(d) && !/chicken[\\s-]?fried|pastrami\\s*burger/i.test(d), skipBars:true, cuisineBlock:/french\\s*(?:bistro|bistrot|brasserie)/i }"
);

// ─── 4. Write file ───────────────────────────────────────────────────────────

fs.writeFileSync(filePath, content, 'utf8');
console.log('Done. index.html updated.');

// Verify code changes landed
const checks = [
  ['bestOfBoost 30', content.includes('const bestOfBoost = flagged ? 30 : 0;')],
  ['skip attractions/coffee', content.includes("cls==='bars'||cls==='attractions'||cls==='coffee'||cls==='dessert'")],
  ['cuisineBlock check', content.includes('if(cat.cuisineBlock && cat.cuisineBlock.test')],
  ['cap at 5', content.includes('hits.slice(0,5)')],
  ['tacos cuisineBlock', content.includes('pan[\\s-]?asian|vietnamese|japanese|sushi|korean|thai|chinese')],
  ['steak cuisineBlock', content.includes('french\\s*(?:bistro|bistrot|brasserie)')],
];
checks.forEach(([label, ok]) => console.log(`  ${ok ? '✓' : '✗'} ${label}`));

