const fs = require('fs');
const content = fs.readFileSync('index.html', 'utf8');

// Extract restaurants by city using regex
function extractCityRestaurants(cityVar, content) {
  // Find the variable assignment
  const varStart = content.indexOf('const ' + cityVar + ' =');
  if (varStart === -1) return [];

  // Find the data - it should be an array
  const arrStart = content.indexOf('[', varStart);
  // We'll just extract names using regex in the city's section
  // Find approximate end by looking for the next 'const ' at similar indent
  const nextVar = content.indexOf('\\nconst ', varStart + 10);
  const section = content.slice(varStart, nextVar > 0 ? nextVar : varStart + 500000);

  const names = [...section.matchAll(/\"name\":\"([^\"]+)\"/g)].map(m => m[1]);
  const cuisines = [...section.matchAll(/\"cuisine\":\"([^\"]+)\"/g)].map(m => m[1]);
  const bestOfs = [...section.matchAll(/\"bestOf\":\[([^\]]+)\]/g)].map(m => m[1]);

  // Build list
  const result = [];
  for (let i = 0; i < names.length; i++) {
    result.push({name: names[i], cuisine: cuisines[i] || '', bestOf: bestOfs[i] || ''});
  }
  return result;
}

const cities = ['SLC_DATA', 'SEATTLE_DATA', 'DALLAS_DATA', 'NYC_DATA', 'LA_DATA', 'AUSTIN_DATA', 'SANANTONIO_DATA', 'HOUSTON_DATA', 'CHICAGO_DATA', 'PHX_DATA', 'SD_DATA', 'LV_DATA'];

for (const city of cities) {
  const rests = extractCityRestaurants(city, content);
  const withBestOf = rests.filter(r => r.bestOf);
  console.log('\\n=== ' + city + ' (' + rests.length + ' restaurants, ' + withBestOf.length + ' with bestOf) ===');
  withBestOf.forEach(r => console.log('  [' + r.cuisine + '] ' + r.name + ' => ' + r.bestOf));
}
