  return desc.includes('speakeasy') || desc.includes('hidden') || desc.includes('password') || 
         desc.includes('unmarked') || desc.includes('no sign') ||
         tags.includes('speakeasy') || tags.includes('hidden') || tags.includes('cocktail bar');
});

